import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        // numeric values: 10, 2, 33, 7, -5  =>  sorted: -5,2,7,10,33
        // note: "007" has value 7, appears at position 3 in sorted output
        String[] result = new Solution().sortStringsNumerically(
            new String[]{"10","2","33","007","-5"}
        );
        assertArrayEquals(new String[]{"-5","2","007","10","33"}, result);
    }

    @Test
    void negatives() {
        // -10 < -3 < 5
        String[] result = new Solution().sortStringsNumerically(
            new String[]{"-3","-10","5"}
        );
        assertArrayEquals(new String[]{"-10","-3","5"}, result);
    }

    @Test
    void stableOnTiedValues() {
        // "7" and "007" both have numeric value 7; stable sort must keep "7" before "007"
        String[] result = new Solution().sortStringsNumerically(
            new String[]{"7","007"}
        );
        assertArrayEquals(new String[]{"7","007"}, result);
    }

    @Test
    void leadingZeros() {
        // all three represent value 0; stable sort preserves input order
        String[] result = new Solution().sortStringsNumerically(
            new String[]{"0","00","000"}
        );
        assertArrayEquals(new String[]{"0","00","000"}, result);
    }

    @Test
    void alreadySorted() {
        String[] result = new Solution().sortStringsNumerically(
            new String[]{"-2","0","1","99"}
        );
        assertArrayEquals(new String[]{"-2","0","1","99"}, result);
    }

    @Test
    void singleElement() {
        String[] result = new Solution().sortStringsNumerically(new String[]{"42"});
        assertArrayEquals(new String[]{"42"}, result);
    }

    @Test
    void empty() {
        String[] result = new Solution().sortStringsNumerically(new String[]{});
        assertArrayEquals(new String[]{}, result);
    }
}
